class Solution {
    public boolean canFinish(int numCourses, int[][] prerequisites) {
        int[] visited = new int[numCourses];
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < numCourses; i++) {
            adj.add(new ArrayList<>());
        }
        for (int[] p : prerequisites) {
            adj.get(p[0]).add(p[1]);
        }
        for (int i = 0; i < numCourses; i++) {
            if (visited[i] == 0 && !dfs(adj, visited, i)) {
                return false;
            }
        }
        return true;
    }

    private boolean dfs(List<List<Integer>> adj, int[] visited, int node) {
        visited[node] = 1; // visiting
        for (int neighbor : adj.get(node)) {
            if (visited[neighbor] == 1) { // cycle detected
                return false;
            }
            if (visited[neighbor] == 0 && !dfs(adj, visited, neighbor)) {
                return false;
            }
        }
        visited[node] = 2; // fully visited
        return true;
    }
}
